package main

import (
    "encoding/json"
    "fmt"
    "os"
    "time"

    "github.com/cilium/tetragon/pkg/defaults"
    "github.com/cilium/tetragon/pkg/process"
    "github.com/cilium/tetragon/pkg/watcher"
    corev1 "k8s.io/api/core/v1"
    metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    "k8s.io/apimachinery/pkg/types"
)

func main() {
    const (
        containerID = "fake_container_id"
        podUID = "11111111-2222-3333-4444-555555555555"
    )

    pod := &corev1.Pod{
        ObjectMeta: metav1.ObjectMeta{
            Namespace: "default",
            Name:      "demo-pod",
            UID:       types.UID(podUID),
        },
        Status: corev1.PodStatus{ContainerStatuses: []corev1.ContainerStatus{{
            Name:        "demo-container",
            ContainerID: "containerd://" + containerID,
        }}},
    }

    if err := process.InitCache(watcher.NewFakeK8sWatcher([]interface{}{pod}), 16, defaults.DefaultProcessCacheGCInterval); err != nil {
        fmt.Fprintf(os.Stderr, "InitCache failed: %v\n", err)
        os.Exit(1)
    }
    defer process.FreeCache()

    podInfo := process.GetPodInfo(containerID, "/bin/true", "", 0)
    if podInfo == nil {
        fmt.Fprintln(os.Stderr, "GetPodInfo returned nil")
        os.Exit(1)
    }

    data, err := json.Marshal(podInfo)
    if err != nil {
        fmt.Fprintf(os.Stderr, "json.Marshal failed: %v\n", err)
        os.Exit(1)
    }

    var got map[string]interface{}
    if err := json.Unmarshal(data, &got); err != nil {
        fmt.Fprintf(os.Stderr, "json.Unmarshal failed: %v\n", err)
        os.Exit(1)
    }
    if got["podUID"] != podUID {
        fmt.Fprintf(os.Stderr, "podUID missing from JSON or wrong value: got %v in %s\n", got["podUID"], data)
        os.Exit(2)
    }

    _ = time.Second // keep time imported if defaults changes in future
    fmt.Printf("podUID included: %s\n", data)
}
EOF
