package main

import (
    "encoding/json"
    "fmt"
    "os"

    "github.com/cilium/tetragon/pkg/defaults"
    "github.com/cilium/tetragon/pkg/process"
    "github.com/cilium/tetragon/pkg/watcher"
    corev1 "k8s.io/api/core/v1"
    metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    "k8s.io/apimachinery/pkg/types"
)

const containerID = "fake_container_id"

func runCase(name string, uid types.UID, wantUID string, wantUIDKey bool) error {
    pod := &corev1.Pod{
        ObjectMeta: metav1.ObjectMeta{
            Namespace: "default",
            Name:      name,
            UID:       uid,
        },
        Status: corev1.PodStatus{ContainerStatuses: []corev1.ContainerStatus{{
            Name:        "demo-container",
            ContainerID: "containerd://" + containerID,
        }}},
    }

    if err := process.InitCache(watcher.NewFakeK8sWatcher([]interface{}{pod}), 16, defaults.DefaultProcessCacheGCInterval); err != nil {
        return fmt.Errorf("InitCache failed: %w", err)
    }
    defer process.FreeCache()

    podInfo := process.GetPodInfo(containerID, "/bin/true", "", 0)
    if podInfo == nil {
        return fmt.Errorf("GetPodInfo returned nil")
    }

    data, err := json.Marshal(podInfo)
    if err != nil {
        return fmt.Errorf("json.Marshal failed: %w", err)
    }

    var got map[string]interface{}
    if err := json.Unmarshal(data, &got); err != nil {
        return fmt.Errorf("json.Unmarshal failed: %w", err)
    }
    gotUID, hasUID := got["uid"]
    if hasUID != wantUIDKey {
        return fmt.Errorf("uid key presence mismatch: got %v want %v in %s", hasUID, wantUIDKey, data)
    }
    if wantUIDKey && gotUID != wantUID {
        return fmt.Errorf("uid wrong value: got %v want %s in %s", gotUID, wantUID, data)
    }

    fmt.Printf("%s: %s\n", name, data)
    return nil
}

func main() {
    cases := []struct {
        name       string
        uid        types.UID
        wantUID    string
        wantUIDKey bool
    }{
        {"pod-with-uid", "11111111-2222-3333-4444-555555555555", "11111111-2222-3333-4444-555555555555", true},
        {"pod-with-empty-uid", "", "", false},
    }

    for _, tc := range cases {
        if err := runCase(tc.name, tc.uid, tc.wantUID, tc.wantUIDKey); err != nil {
            fmt.Fprintf(os.Stderr, "%s failed: %v\n", tc.name, err)
            os.Exit(1)
        }
    }
}
EOF
